// Auto-generated word pool for Wordle
export const compressedValidWords: Record<number, string> = {
    4: '',
    5: '',
    6: ''
};

// Top 500 words for each length are used as possible solutions
export const compressedSolutionWords: Record<number, string> = {
    4: '',
    5: '',
    6: ''
};

export function isValidWord(word: string): boolean {
    const len = word.length;
    const pool = compressedValidWords[len];
    if (!pool) return false;

    // In a compressed string of fixed-length words, check if it's a multiple of length
    const idx = pool.indexOf(word.toLowerCase());
    return idx !== -1 && idx % len === 0;
}

export function getRandomSolution(length: number): string | undefined {
    const pool = compressedSolutionWords[length];
    if (!pool) return undefined;

    const wordCount = pool.length / length;
    if (wordCount === 0) return undefined;

    const randomIdx = Math.floor(Math.random() * wordCount) * length;
    return pool.substring(randomIdx, randomIdx + length);
}
